# Explorer: complete from packet starter + instruction contract
def assess(record: dict) -> str:
    required = {'query', 'expected_top', 'version', 'metric', 'case_id', 'docs'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('query') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT_EMBEDDING_RANK'

valid = {"case_id": 'CASO-SYN-1A', 'query': True, 'docs': True, 'metric': 'precision_at_k', 'version': True, 'expected_top': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'query': False, 'docs': False, 'metric': 'precision_at_k', 'version': False, 'expected_top': False}
missing = {k: valid[k] for k in valid if k != 'expected_top'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

